/**
 * Calculates (base^exp) % mod
 * @param {bigint} base
 * @param {bigint} exp
 * @param {bigint} mod
 * @returns {bigint}
 */
const power = (base, exp, mod) => {
    let res = 1n;
    base %= mod;
    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2n;
    }
    return res;
};

/**
 * Precomputes factorials and inverse factorials for combinations.
 */
class Combinatorics {
    constructor(maxN, mod) {
        this.mod = BigInt(mod);
        this.fact = new Array(maxN + 1);
        this.invFact = new Array(maxN + 1);
        this.fact[0] = 1n;
        for (let i = 1; i <= maxN; i++) {
            this.fact[i] = (this.fact[i - 1] * BigInt(i)) % this.mod;
        }
        this.invFact[maxN] = power(this.fact[maxN], this.mod - 2n, this.mod);
        for (let i = maxN - 1; i >= 0; i--) {
            this.invFact[i] = (this.invFact[i + 1] * BigInt(i + 1)) % this.mod;
        }
    }

    /**
     * Calculates C(n, k) % mod
     * @param {number} n
     * @param {number} k
     * @returns {bigint}
     */
    C(n, k) {
        if (k < 0 || k > n) {
            return 0n;
        }
        return (this.fact[n] * this.invFact[k] % this.mod) * this.invFact[n - k] % this.mod;
    }
}

/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @returns {number}
 */
const solve = (n, pos, k) => {
    const MOD = 1000000000 + 7;
    const M = BigInt(MOD);

    // Left side: people at indices 0 to pos - 1. There are 'pos' people.
    const L_count = pos;
    // Right side: people at indices pos + 1 to n - 1. There are 'n - 1 - pos' people.
    const R_count = n - 1 - pos;

    // The person at 'pos' can choose 'L' or 'R' independently, contributing a factor of 2.

    // 1. Contribution from the left side (i < pos):
    // An index i < pos is visible if they choose 'L'.
    // We need to choose 'l_k' people out of 'L_count' to choose 'L' such that l_k is the number seen from the left.
    // Since the problem statement implies that 'i < pos' is visible iff they choose 'L', 
    // the number seen from the left is exactly the count of people on the left who choose 'L'.
    // Let l_k be the number of people on the left who choose 'L'. We need to choose l_k such that l_k <= k.
    // The number of ways to have exactly l_k people on the left choose 'L' is C(L_count, l_k).

    // 2. Contribution from the right side (i > pos):
    // An index i > pos is visible if they choose 'R'.
    // Similarly, let r_k be the number of people on the right who choose 'R'. We need r_k + l_k = k.
    // The number of ways to have exactly r_k people on the right choose 'R' is C(R_count, r_k).

    // Total ways to achieve k seen people (excluding pos):
    // Sum over all possible l_k from 0 to L_count:
    //   Ways = C(L_count, l_k) * C(R_count, k - l_k)

    let total_ways_excluding_pos = 0n;

    // We need C(n, k) for up to n=10^5.
    const comb = new Combinatorics(n, MOD);

    for (let l_k = 0; l_k <= L_count; l_k++) {
        const r_k = k - l_k;

        // Check bounds for r_k
        if (r_k >= 0 && r_k <= R_count) {
            const ways_left = comb.C(L_count, l_k);
            const ways_right = comb.C(R_count, r_k);

            const ways_current = (ways_left * ways_right) % M;
            total_ways_excluding_pos = (total_ways_excluding_pos + ways_current) % M;
        }
    }

    // The person at 'pos' can choose 'L' or 'R' (2 ways), and this choice does not affect the visibility count k.
    // Total answer = (Total ways excluding pos) * 2

    let final_answer = (total_ways_excluding_pos * 2n) % M;

    return Number(final_answer);
};

